const msg  = $json.messages[0];
const type = msg.image    ? 'image'
           : msg.document ? 'document'
           : msg.video    ? 'video'
           : msg.audio    ? 'audio'
           : 'media';
const mediaObj = msg[type] || {};
const media_url = mediaObj.url || '';

// Audio has no caption or filename — use sensible defaults
const caption  = mediaObj.caption  || '';
const filename = mediaObj.filename || (type === 'audio' ? 'voice_message.ogg' : '');
const msgText  = caption || `[${type} received]`;

return [{ json: {
  wa_id:             $json.contacts[0].wa_id,
  name:              $json.contacts[0].profile?.name || '',
  caption,
  media_id:          mediaObj.id || '',
  media_url,
  media_type:        type,
  mime_type:         mediaObj.mime_type || '',
  filename,
  tsMs:              Number($json.messages[0].timestamp || 0) * 1000,
  tsIso:             new Date(Number($json.messages[0].timestamp || 0) * 1000).toISOString(),
  escalation_reason: 'media_received',
  msgText,
  // voice-specific flag — useful if you want to transcribe later
  is_voice:          type === 'audio' && mediaObj.voice === true,
}}];

// Merge the stable_url back onto the original media info
const download = $json; // response from Download Media API
const extract  = $('Extract Media Info').item.json;

const stable_url = download.ok
  ? download.stable_url
  : extract.media_url; // fall back to original WhatsApp URL if download failed

return [{ json: {
  ...extract,
  media_url: stable_url,  // overwrite with stable internal URL
  download_ok: download.ok ?? false,
}}];

const wa_id  = $('Extract Sender ID').first().json.wa_id || '';
const digits = wa_id.replace(/\D/g, '');

let countries = [];
try { countries = $('countrycodes').all().map(i => i.json); } catch(e) {}

const sorted = [...countries].sort((a, b) =>
  b.code.replace(/\D/g,'').length - a.code.replace(/\D/g,'').length
);

let match = null;
for (const c of sorted) {
  const prefix = c.code.split(',')[0].replace(/\D/g,'');
  if (digits.startsWith(prefix)) { match = c; break; }
}

return [{ json: {
  ...$json,
  phone_country_code: match?.code    || null,
  phone_country_name: match?.country || null,
  phone_country_iso:  match?.iso     || null,
  phone_flag_url:     match?.flag_url || null,
  _resolvedCountry:   match?.country || null,
}}];

const src = $('Extract Sender ID').item.json;
const wa_id = src.wa_id;
const name = src.name;
const tsMs = Number(src.tsMs);
// compute useful times
const tsIso = (src.tsIso || new Date(tsMs || Date.now()).toISOString()).trim();
const sessionId = `${wa_id}_${String(tsMs).slice(0,10)}`;
const sessionStartIso = (src.sessionStartIso || tsIso).trim();
// 120-day TTL (optional)
const ttlDays = 120;
const ttlIso = new Date(Date.now() + ttlDays*86400*1000).toISOString();

return [{
  ...src,
  wa_id,
  name,
  tsMs,
  tsIso,
  sessionId,
  sessionStartIso,
  ttlIso,
  direction: src.direction || 'inbound',
  projectId: 'neema-6037c',
  mergeKey: 1,                  // <- number, not string
}];

// === Detect Media Request ===
// Flags any inbound TEXT message that requests media the AI cannot send:
// images, PDFs, catalogues, brochures, videos, files.
//
// IMPORTANT: Skip entirely when the inbound message was a voice note.
// Pattern-matching a Whisper transcription against media-request keywords
// causes false positives — words like "audio", "send", "share" appear
// naturally in speech and incorrectly escalate to human mode, preventing
// the AI from replying with TTS audio as intended.
const isAudio = $('Extract Sender ID').item.json.isAudio === true;
if (isAudio) {
  return [{ ...$json, isMediaRequest: false, mediaEscalationReason: null }];
}

const imageAnalysis = $('Extract Sender ID').item.json.imageAnalysis || '';
if (imageAnalysis) {
  return [{ ...$json, isMediaRequest: false, mediaEscalationReason: null }];
}

const msgText = String(
  $json?.msgText ||
  $json?.messages?.[0]?.text?.body ||
  ""
).toLowerCase().trim();

// ── Media intent patterns ────────────────────────────────────
const MEDIA_PATTERNS = [
  // ── Bare colloquial nouns (catch "need to see pics", "send pics", "any photos?") ──
  /\bpics?\b/i,
  /\bphotos?\b/i,
  /\bimages?\b/i,
  /\bpictures?\b/i,
  /\bphotographs?\b/i,
  /\bcatalogue\b/i,
  /\bcatalog\b/i,
  /\bbrochure\b/i,
  /\bflyer\b/i,
  /\blookbook\b/i,
  /\bprice\s*list\b/i,
  /\bpdf\b/i,
  /\bvoice\s*note\b/i,
  /\bvoice\s*message\b/i,
  /\bvideo\b/i,
  /\baudio\b/i,
  /\battachment\b/i,
  // ── Swahili variants ──
  /\bpicha\b/i,
  /\bkatalogi\b/i,
  /\bbrosha\b/i,
  /\bsauti\b/i,
  // ── "show me", "see", "view" + visual intent ──
  /\b(show|see|view|look\s+at|check\s+out)\b.{0,30}\b(item|product|cassock|gown|alb|shirt|collar|tray|communion|stock|what\s+you\s+have|what\s+you\s+got)\b/i,
  // ── Explicit send/share + file type (kept from before) ──
  /\b(send|share|attach|forward|drop|give|email|whatsapp)\b.{0,40}\b(image|photo|pic|pdf|catalogue|catalog|brochure|flyer|document|file|attachment)\b/i,
];

const isMediaRequest = MEDIA_PATTERNS.some(rx => rx.test(msgText));
return [{
  ...$json,
  isMediaRequest,
  mediaEscalationReason: isMediaRequest
    ? "Customer requested media/image/file — AI cannot send attachments"
    : null,
}];

