// === Media Escalation Handler ===
// Silently escalates to a human agent — no message sent to the customer.
// The agent will see the conversation flagged in their inbox and can
// respond directly with the requested media.

const wa_id   = String($json?.wa_id || "").trim();
const msgText = String($json?.msgText || "").trim();

if (!wa_id) throw new Error("Media Escalation: wa_id missing");

// Notification text shown to the agent in the inbox
const agentNote =
  `📎 Media request from ${wa_id}: "${msgText.slice(0, 120)}${msgText.length > 120 ? '…' : ''}" — ` +
  `customer is asking for images or files. Please respond with the relevant media.`;

return [{
  wa_id,
  reply_text:          null,       // no message sent to customer
  escalationNote:      agentNote,
  isMediaRequest:      true,
  needsHumanIntercept: true,
  sessionId:           $json?.sessionId || null,
  mergeKey:            $json?.mergeKey  || 1,
  msgText,
}];
